// ====================================================================
// Datumskontext und Quellen-Konfiguration (KOMPLETT v2.0)
// 16 geprüfte RSS-Feed-URLs – Stand 04.05.2026
// ====================================================================

const heute = new Date();
const datumISO = heute.toISOString().split('T')[0];
const datumDE = heute.toLocaleDateString('de-DE', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

const quellen = [
  { name: 'Heise Online IT',                  url: 'https://www.heise.de/rss/heise-atom.xml',                                                        kategorie: 'Digitalisierung & IT' },
  { name: 'Markt und Mittelstand',             url: 'https://www.marktundmittelstand.de/rss.xml',                                                     kategorie: 'Mittelstand Allgemein' },
  { name: 'Handelsblatt Unternehmen',          url: 'https://www.handelsblatt.com/contentexport/feed/unternehmen',                                     kategorie: 'Mittelstand & Strategie' },
  { name: 'WirtschaftsWoche Unternehmen',      url: 'https://www.wiwo.de/contentexport/feed/rss/unternehmen',                                          kategorie: 'Mittelstand & Wirtschaft' },
  { name: 't3n Digital Business',              url: 'https://t3n.de/rss.xml',                                                                         kategorie: 'Digitalisierung & IT' },
  { name: 'Impulse Unternehmer-Magazin',       url: 'https://www.impulse.de/feed',                                                                     kategorie: 'Mittelstand & Strategie' },
  { name: 'Gründerszene',                      url: 'https://www.gruenderszene.de/feed',                                                               kategorie: 'Startups & Innovation' },
  { name: 'Deutsche Handwerks Zeitung',        url: 'https://www.deutsche-handwerks-zeitung.de/feed/',                                                 kategorie: 'Handwerk & KMU' },
  { name: 'FAZ Wirtschaft',                    url: 'https://www.faz.net/rss/aktuell/wirtschaft/',                                                     kategorie: 'Wirtschaftspolitik & Regulierung' },
  { name: 'Tagesschau Wirtschaft',             url: 'https://www.tagesschau.de/wirtschaft/index~rss2.xml',                                             kategorie: 'Wirtschaftspolitik & Regulierung' },
  { name: 'Spiegel Wirtschaft',                url: 'https://www.spiegel.de/wirtschaft/index.rss',                                                     kategorie: 'Wirtschaft Allgemein' },
  { name: 'Google News - KMU Mittelstand',     url: 'https://news.google.com/rss/search?q=KMU+Mittelstand+Deutschland&hl=de&gl=DE&ceid=DE:de',         kategorie: 'Allgemeine KMU-Nachrichten' },
  { name: 'Google News - Digitalisierung',     url: 'https://news.google.com/rss/search?q=Digitalisierung+Mittelstand&hl=de&gl=DE&ceid=DE:de',         kategorie: 'Digitalisierung' },
  { name: 'Google News - Fachkräftemangel',    url: 'https://news.google.com/rss/search?q=Fachkr%C3%A4ftemangel+Mittelstand&hl=de&gl=DE&ceid=DE:de',   kategorie: 'Personal & Fachkräfte' },
  { name: 'Google News - Maschinenbau Elektro',url: 'https://news.google.com/rss/search?q=Maschinenbau+OR+Elektrotechnik+Mittelstand&hl=de&gl=DE&ceid=DE:de', kategorie: 'Branchenspezifisch' },
  { name: 'Google News - Autohandel',          url: 'https://news.google.com/rss/search?q=Autohandel+OR+Kfz-Handel+Deutschland&hl=de&gl=DE&ceid=DE:de', kategorie: 'Kfz-Handel' }
];

return [{ json: { datum: datumISO, datumDE, quellen, quellenAnzahl: quellen.length } }];

// Quellen-Splitter: Ein Item pro Quelle
const config = $input.first().json;
return config.quellen.map(q => ({ json: { ...q, datum: config.datum, datumDE: config.datumDE } }));

// ====================================================================
// Fehlerfilter & RSS-XML-Validierung
// Filtert HTTP-Fehler, leere Antworten und Nicht-XML heraus
// ====================================================================

const items = $input.all();
const erfolgreiche = [];
const fehlerhafte = [];

for (const item of items) {
  const data = item.json;

  if (data.error || (data.statusCode && data.statusCode >= 400)) {
    fehlerhafte.push({ name: data.name || '?', fehler: data.error?.message || `HTTP ${data.statusCode}` });
    continue;
  }

  const body = typeof data.data === 'string' ? data.data
             : typeof data.response === 'string' ? data.response
             : typeof data.body === 'string' ? data.body : '';

  if (!body || body.trim().length === 0) {
    fehlerhafte.push({ name: data.name || '?', fehler: 'Leere Antwort' });
    continue;
  }

  if (!(body.includes('<rss') || body.includes('<feed') || body.includes('<?xml'))) {
    fehlerhafte.push({ name: data.name || '?', fehler: 'Kein RSS/XML' });
    continue;
  }

  erfolgreiche.push({ json: {
    name: data.name, url: data.url, kategorie: data.kategorie,
    datum: data.datum, datumDE: data.datumDE, rssContent: body
  }});
}

if (fehlerhafte.length > 0) {
  console.log(`⚠️ ${fehlerhafte.length} Feeds fehlgeschlagen:`);
  fehlerhafte.forEach(f => console.log(`  ❌ ${f.name}: ${f.fehler}`));
}
console.log(`✅ ${erfolgreiche.length} Feeds erfolgreich`);

if (erfolgreiche.length === 0) {
  throw new Error(`Alle ${items.length} Feeds fehlgeschlagen!`);
}

return erfolgreiche;

// ====================================================================
// FEATURE 1: XML-Parser - Strukturierte Daten aus RSS/Atom XML
// Extrahiert pro Feed max. 10 Artikel: Titel, Beschreibung, Link,
// Datum, Autor. Spart KI-Tokens durch Vorverarbeitung.
// ====================================================================

const items = $input.all();
const alleParsed = [];

function getTag(xml, tag) {
  const re = new RegExp(
    '<' + tag + '[^>]*><!\\[CDATA\\[([\\s\\S]*?)\\]\\]><\\/' + tag + '>'
    + '|<' + tag + '[^>]*>([\\s\\S]*?)<\\/' + tag + '>', 'i');
  const m = xml.match(re);
  return (m ? (m[1] || m[2] || '') : '').trim();
}

function cleanHtml(s) {
  return s.replace(/<[^>]+>/g, '')
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"').replace(/&#0?39;/g, "'").replace(/\s+/g, ' ')
    .substring(0, 500);
}

for (const item of items) {
  const rssContent = item.json.data || item.json.rssContent || item.json.content || '';
  const name = item.json.name || item.json.url || 'Unbekannt';
  const url = item.json.url || '';
  const kategorie = item.json.kategorie || '';
  const datum = item.json.datum || '';
  const datumDE = item.json.datumDE || '';

  if (!rssContent) continue;

  const artikel = [];

  // --- RSS 2.0 ---
  if (rssContent.includes('<rss') || (rssContent.includes('<channel') && !rssContent.includes('<feed'))) {
    const matches = rssContent.match(/<item[\s>][\s\S]*?<\/item>/gi) || [];
    for (const m of matches.slice(0, 10)) {
      const titel = getTag(m, 'title');
      if (!titel) continue;
      artikel.push({
        titel: titel,
        link: getTag(m, 'link'),
        beschreibung: cleanHtml(getTag(m, 'description')),
        datum: getTag(m, 'pubDate') || getTag(m, 'dc:date'),
        autor: getTag(m, 'dc:creator') || getTag(m, 'author')
      });
    }
  }

  // --- Atom ---
  if (rssContent.includes('<feed')) {
    const matches = rssContent.match(/<entry[\s>][\s\S]*?<\/entry>/gi) || [];
    for (const m of matches.slice(0, 10)) {
      const titel = getTag(m, 'title');
      if (!titel) continue;
      const linkMatch = m.match(/<link[^>]*href=["']([^"']+)["'][^>]*\/?>/);
      const autorMatch = m.match(/<author>[\s\S]*?<name>([\s\S]*?)<\/name>[\s\S]*?<\/author>/i);
      artikel.push({
        titel: titel,
        link: linkMatch ? linkMatch[1] : '',
        beschreibung: cleanHtml(getTag(m, 'summary') || getTag(m, 'content')),
        datum: getTag(m, 'published') || getTag(m, 'updated'),
        autor: autorMatch ? autorMatch[1].trim() : ''
      });
    }
  }

  if (artikel.length > 0) {
    alleParsed.push({ json: {
      quelleName: name,
      quelleUrl: url,
      kategorie: kategorie,
      datum: datum,
      datumDE: datumDE,
      artikelAnzahl: artikel.length,
      artikel: artikel
    }});
  }
}

const total = alleParsed.reduce(function(s, i) { return s + i.json.artikelAnzahl; }, 0);
console.log('Quellen geparst: ' + alleParsed.length + ', Artikel extrahiert: ' + total);
if (alleParsed.length === 0) throw new Error('Keine Artikel extrahiert!');
return alleParsed;

// ====================================================================
// Artikel-Aggregator: Fasst alle Quellen zusammen, erstellt
// Token-optimierten Text-Input für den KI-Node
// ====================================================================

const items = $input.all();
const datum   = items[0]?.json?.datum   || new Date().toISOString().split('T')[0];
const datumDE = items[0]?.json?.datumDE || '';

const alleArtikel = [];
for (const item of items) {
  for (const a of item.json.artikel) {
    alleArtikel.push({
      titel: a.titel, quelle: item.json.quelleName,
      kategorie: item.json.kategorie, link: a.link,
      beschreibung: a.beschreibung, datum: a.datum, autor: a.autor
    });
  }
}

const artikelText = alleArtikel.map((a, i) =>
  `[${i+1}] ${a.titel}\nQuelle: ${a.quelle} | Kategorie: ${a.kategorie}\n${a.beschreibung}\nLink: ${a.link}\nDatum: ${a.datum}${a.autor ? ' | Autor: '+a.autor : ''}`
).join('\n---\n');

console.log(`📊 ${alleArtikel.length} Artikel aggregiert aus ${items.length} Quellen`);

return [{ json: { datum, datumDE, artikelAnzahl: alleArtikel.length, quellenAnzahl: items.length, artikelText, artikelRaw: alleArtikel } }];

// ====================================================================
// FEATURE 5: KI-Ergebnisse als JSON-Datei speichern
// Pfad: /tmp/kmu_news_YYYY-MM-DD.json
// ====================================================================

const input = $input.first().json;
let kiAntwort;

const raw = input.message?.content || input.text || input.output || JSON.stringify(input);

try {
  if (typeof raw === 'string') {
    const m = raw.match(/\{[\s\S]*\}/);
    kiAntwort = m ? JSON.parse(m[0]) : JSON.parse(raw);
  } else {
    kiAntwort = raw;
  }
} catch (e) {
  console.log('⚠️ JSON-Parse fehlgeschlagen, speichere Rohdaten');
  kiAntwort = {
    datum: new Date().toISOString().split('T')[0],
    fehler: 'KI-Antwort nicht parsbar',
    rohdaten: String(raw).substring(0, 5000)
  };
}

const ergebnis = {
  meta: {
    workflow: 'KMU News Workflow KOMPLETT',
    erstellt_am: new Date().toISOString(),
    version: '2.0'
  },
  ergebnis: kiAntwort
};

const datum = kiAntwort.datum || new Date().toISOString().split('T')[0];
const pfad  = `/tmp/kmu_news_${datum}.json`;

require('fs').writeFileSync(pfad, JSON.stringify(ergebnis, null, 2), 'utf8');

console.log(`💾 Gespeichert: ${pfad}`);
console.log(`📰 ${kiAntwort.nachrichten?.length || 0} Nachrichten, ${kiAntwort.trends?.length || 0} Trends`);

return [{ json: {
  status: 'gespeichert', dateipfad: pfad,
  nachrichtenAnzahl: kiAntwort.nachrichten?.length || 0,
  ergebnis
}}];
